  1→import { useCallback, useEffect } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { TOOLS } from '@/editor/tools';
  6→import { detectRooms } from '@/geometry/roomDetection';
  7→import { createRoom } from '@/domain/models';
  8→import { isTypingTarget } from '@/utils/keyboard';
  9→import {
 10→  NewIcon, SaveIcon, LoadIcon, UndoIcon, RedoIcon,
 11→  CopyIcon, CutIcon, PasteIcon,
 12→  SelectIcon, DimensionIcon, WallIcon, BeamIcon, StairIcon,
 13→  SectionCutIcon, SlabIcon, RoomIcon, DoorIcon, WindowIcon,
 14→  ColumnIcon, LandingIcon,
 15→  KitchenTopIcon, ToiletIcon, LavatoryIcon, TableIcon, TVIcon, SofaIcon, BedIcon,
 16→  GridIcon, SnapIcon, DetectRoomsIcon,
 17→  SidebarIcon, PropertiesIcon,
 18→} from './ToolbarIcons';
 19→import { FIXTURE_TYPES } from '@/editor/tools';
 20→import styles from './Toolbar.module.css';
 21→
 22→const viewModes = [
 23→  { key: 'plan', label: 'Plan', viewMode: 'plan' },
 24→  { key: 'front', label: 'Front', viewMode: 'elevation_front' },
 25→  { key: 'rear', label: 'Rear', viewMode: 'elevation_rear' },
 26→  { key: 'left', label: 'Left', viewMode: 'elevation_left' },
 27→  { key: 'right', label: 'Right', viewMode: 'elevation_right' },
 28→  { key: 'section', label: 'Section', viewMode: 'section_view' },
 29→];
 30→
 31→const toolItems = [
 32→  { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
 33→  { tool: TOOLS.DIMENSION, label: 'Dimension', shortcut: 'M', Icon: DimensionIcon },
 34→  { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W', Icon: WallIcon },
 35→  { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B', Icon: BeamIcon },
 36→  { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T', Icon: StairIcon },
 37→  { tool: TOOLS.SECTION, label: 'Section Cut', shortcut: 'Q', Icon: SectionCutIcon },
 38→  { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S', Icon: SlabIcon },
 39→  { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R', Icon: RoomIcon },
 40→  { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', Icon: DoorIcon },
 41→  { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N', Icon: WindowIcon },
 42→  { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C', Icon: ColumnIcon },
 43→  { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L', Icon: LandingIcon },
 44→];
 45→
 46→export default function Toolbar({
 47→  onNew,
 48→  onSave,
 49→  onLoad,
 50→  isSidebarCollapsed,
 51→  isPropertiesCollapsed,
 52→  onToggleSidebar,
 53→  onToggleProperties,
 54→}) {
 55→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, toolState, dispatch: editorDispatch } = useEditor();
 56→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 57→  const {
 58→    canCopySelection,
 59→    canPaste,
 60→    copySelection,
 61→    cutSelection,
 62→    beginPaste,
 63→  } = usePlanClipboardController();
 64→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 65→
 66→  const fixtureItems = [
 67→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 68→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 69→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 70→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 71→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 72→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 73→    { fixtureType: FIXTURE_TYPES.BED, label: 'Bed', Icon: BedIcon },
 74→  ];
 75→
 76→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 77→
 78→  const handleUndo = useCallback(() => {
 79→    if (!canUndo) return;
 80→    dispatch({ type: 'UNDO' });
 81→    editorDispatch({ type: 'DESELECT' });
 82→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 83→  }, [canUndo, dispatch, editorDispatch]);
 84→
 85→  const handleRedo = useCallback(() => {
 86→    if (!canRedo) return;
 87→    dispatch({ type: 'REDO' });
 88→    editorDispatch({ type: 'DESELECT' });
 89→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 90→  }, [canRedo, dispatch, editorDispatch]);
 91→
 92→  const handleDetectRooms = () => {
 93→    const floor = project.floors.find(f => f.id === activeFloorId);
 94→    if (!floor || floor.walls.length < 3) {
 95→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
 96→      return;
 97→    }
 98→    const detected = detectRooms(floor.walls, floor.columns || []);
 99→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
100→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
101→    editorDispatch({ type: 'DESELECT' });
102→    editorDispatch({
103→      type: 'SET_STATUS_MESSAGE',
104→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
105→    });
106→  };
107→
108→  useEffect(() => {
109→    const handleKeyDown = (e) => {
110→      if (!(e.ctrlKey || e.metaKey)) return;
111→      if (isTypingTarget(e.target)) return;
112→
113→      const key = e.key.toLowerCase();
114→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
115→      const isUndo = key === 'z' && !e.shiftKey;
116→      if (!isUndo && !isRedo) return;
117→
118→      e.preventDefault();
119→      if (isRedo) {
120→        handleRedo();
121→        return;
122→      }
123→      handleUndo();
124→    };
125→
126→    window.addEventListener('keydown', handleKeyDown);
127→    return () => window.removeEventListener('keydown', handleKeyDown);
128→  }, [handleRedo, handleUndo]);
129→
130→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
131→    viewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
132→
133→  return (
134→    <div className={styles.toolbar}>
135→      {/* File & clipboard actions */}
136→      <div className={styles.group}>
137→        <button className={styles.btn} onClick={onNew} title="New Project">
138→          <NewIcon className={styles.icon} />
139→        </button>
140→        <button
141→          className={styles.btn}
142→          onClick={handleUndo}
143→          disabled={!canUndo}
144→          title="Undo (Ctrl+Z)"
145→          aria-label="Undo"
146→        >
147→          <UndoIcon className={styles.icon} />
148→        </button>
149→        <button
150→          className={styles.btn}
151→          onClick={handleRedo}
152→          disabled={!canRedo}
153→          title="Redo (Ctrl+Shift+Z)"
154→          aria-label="Redo"
155→        >
156→          <RedoIcon className={styles.icon} />
157→        </button>
158→        <button
159→          className={styles.saveBtn}
160→          onClick={onSave}
161→          title="Save (Ctrl+S)"
162→          data-dirty={isDirty}
163→        >
164→          <SaveIcon className={styles.icon} />
165→        </button>
166→        <div className={styles.divider} />
167→        <button className={styles.btn} onClick={onLoad} title="Load Project">
168→          <LoadIcon className={styles.icon} />
169→        </button>
170→        <button
171→          className={styles.btn}
172→          onClick={copySelection}
173→          disabled={!canCopySelection}
174→          title="Copy (Ctrl+C)"
175→        >
176→          <CopyIcon className={styles.icon} />
177→        </button>
178→        <button
179→          className={styles.btn}
180→          onClick={cutSelection}
181→          disabled={!canCopySelection}
182→          title="Cut (Ctrl+X)"
183→        >
184→          <CutIcon className={styles.icon} />
185→        </button>
186→        <button
187→          className={styles.btn}
188→          onClick={() => beginPaste()}
189→          disabled={!canPaste}
190→          title="Paste (Ctrl+V)"
191→        >
192→          <PasteIcon className={styles.icon} />
193→        </button>
194→      </div>
195→
196→      {/* View mode segmented control */}
197→      <div className={styles.segmentedGroup}>
198→        {viewModes.map(({ key, label, viewMode: vm }) => (
199→          <button
200→            key={key}
201→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
202→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
203→            title={`${label} View`}
204→          >
205→            {label}
206→          </button>
207→        ))}
208→        <button
209→          className={activeViewKey === 'sheets' ? styles.segmentedBtnActive : styles.segmentedBtn}
210→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
211→          title="Sheet Workspace"
212→        >
213→          Sheets
214→        </button>
215→      </div>
216→
217→      {/* Tool palette - inline row of 12 icons */}
218→      <div className={styles.toolPalette}>
219→        {toolItems.map(({ tool, label, shortcut, Icon }) => (
220→          <button
221→            key={tool}
222→            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
223→            onClick={() => setTool(tool)}
224→            disabled={!isPlanView}
225→            title={`${label} (${shortcut})`}
226→            aria-label={label}
227→          >
228→            <Icon className={styles.toolPaletteIcon} />
229→          </button>
230→        ))}
231→      </div>
232→
233→      {/* Fixtures palette */}
234→      <div className={styles.fixturePalette}>
235→        <span className={styles.fixturePaletteLabel}>Fixtures</span>
236→        {fixtureItems.map(({ fixtureType, label, Icon }) => {
237→          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
238→          return (
239→            <button
240→              key={fixtureType}
241→              className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
242→              onClick={() => {
243→                editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
244→                editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
245→              }}
246→              disabled={!isPlanView}
247→              title={`${label} (F)`}
248→              aria-label={label}
249→            >
250→              <Icon className={styles.toolPaletteIcon} />
251→            </button>
252→          );
253→        })}
254→      </div>
255→
256→      {/* Panel toggles & utility toggles */}
257→      <div className={styles.group}>
258→        <button
259→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
260→          onClick={onToggleSidebar}
261→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
262→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
263→        >
264→          <SidebarIcon className={styles.icon} />
265→        </button>
266→        <button
267→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
268→          onClick={onToggleProperties}
269→          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
270→          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
271→        >
272→          <PropertiesIcon className={styles.icon} />
273→        </button>
274→        <div className={styles.divider} />
275→        <button
276→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
277→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
278→          title="Toggle Grid"
279→          aria-label="Toggle Grid"
280→        >
281→          <GridIcon className={styles.icon} />
282→        </button>
283→        <button
284→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
285→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
286→          title="Toggle Snap"
287→          aria-label="Toggle Snap"
288→        >
289→          <SnapIcon className={styles.icon} />
290→        </button>
291→        <button
292→          className={styles.btn}
293→          onClick={handleDetectRooms}
294→          title="Auto-detect Rooms"
295→          disabled={!isPlanView}
296→          aria-label="Auto-detect Rooms"
297→        >
298→          <DetectRoomsIcon className={styles.icon} />
299→        </button>
300→      </div>
301→
302→      <div className={styles.spacer} />
303→    </div>
304→  );
305→}
