  1→import { columnOutline } from '@/geometry/columnGeometry';
  2→import { fixtureOutline } from '@/geometry/fixtureGeometry';
  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { getLandingRenderData } from '@/geometry/landingGeometry';
  5→import { getStairRenderData } from '@/geometry/stairGeometry';
  6→import { getSlabRenderData } from '@/geometry/slabGeometry';
