 11→const HANDLE_SIZE = 8; // px, will use vectorEffect
 12→
 13→function WallSelection({ wall, columns, zoom }) {
 14→  const outline = getWallRenderData(wall, columns || []).outline;
 15→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 16→  const handleR = HANDLE_SIZE / zoom;
 17→
 18→  return (
 19→    <g>
 20→      <polygon
 21→        points={points}
 22→        fill="var(--color-selection-fill)"
 23→        stroke="var(--color-selection)"
 24→        strokeWidth={2}
 25→        strokeDasharray="6 3"
 26→        vectorEffect="non-scaling-stroke"
 27→      />
 28→      {/* Endpoint handles */}
 29→      <rect
 30→        data-handle="start"
 31→        x={wall.start.x - handleR / 2}
 32→        y={wall.start.y - handleR / 2}
 33→        width={handleR}
 34→        height={handleR}
 35→        fill="white"
 36→        stroke="var(--color-selection)"
 37→        strokeWidth={2}
 38→        vectorEffect="non-scaling-stroke"
 39→        style={{ cursor: 'move' }}
 40→      />
 41→      <rect
 42→        data-handle="end"
 43→        x={wall.end.x - handleR / 2}
 44→        y={wall.end.y - handleR / 2}
 45→        width={handleR}
 46→        height={handleR}
 47→        fill="white"
 48→        stroke="var(--color-selection)"
 49→        strokeWidth={2}
 50→        vectorEffect="non-scaling-stroke"
 51→        style={{ cursor: 'move' }}
 52→      />
 53→    </g>
 54→  );
 55→}
