 57→export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
 58→  if (!selectedId || !floor) return null;
 59→
 60→  if (selectedType === 'slab') {
 61→    const slab = (floor.slabs || []).find(s => s.id === selectedId) || null;
 62→    const renderData = slab ? getSlabRenderData(slab) : null;
 63→    if (!renderData) return null;
 64→
 65→    const handleR = HANDLE_SIZE / zoom;
 66→    return (
 67→      <g>
 68→        <polygon
 69→          points={renderData.points}
 70→          fill="var(--color-selection-fill)"
 71→          stroke="var(--color-selection)"
 72→          strokeWidth={2}
 73→          strokeDasharray="6 3"
 74→          vectorEffect="non-scaling-stroke"
 75→        />
 76→        {renderData.outline.map((point, index) => (
 77→          <rect
 78→            key={`${point.x}-${point.y}-${index}`}
 79→            data-handle="slab-vertex"
 80→            data-index={index}
 81→            x={point.x - handleR / 2}
 82→            y={point.y - handleR / 2}
 83→            width={handleR}
 84→            height={handleR}
 85→            fill="white"
 86→            stroke="var(--color-selection)"
 87→            strokeWidth={2}
 88→            vectorEffect="non-scaling-stroke"
 89→            style={{ cursor: 'move' }}
 90→          />
 91→        ))}
 92→      </g>
 93→    );
 94→  }
 95→
 96→  if (selectedType === 'wall') {
 97→    const wall = floor.walls.find(w => w.id === selectedId);
 98→    if (!wall) return null;
 99→    return <WallSelection wall={wall} columns={floor.columns || []} zoom={zoom} />;
100→  }
101→
102→  if (selectedType === 'sectionCut') {
103→    const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId) || null;
104→    const renderData = getSectionCutRenderData(sectionCut);
105→    if (!renderData) return null;
106→    const handleR = HANDLE_SIZE / zoom;
107→
108→    return (
109→      <g>
110→        <line
111→          x1={renderData.line.start.x}
112→          y1={renderData.line.start.y}
113→          x2={renderData.line.end.x}
114→          y2={renderData.line.end.y}
115→          stroke="var(--color-selection)"
116→          strokeWidth={2}
117→          strokeDasharray="6 3"
118→          vectorEffect="non-scaling-stroke"
119→        />
120→        <rect
121→          data-handle="start"
122→          x={sectionCut.startPoint.x - handleR / 2}
123→          y={sectionCut.startPoint.y - handleR / 2}
124→          width={handleR}
125→          height={handleR}
126→          fill="white"
127→          stroke="var(--color-selection)"
128→          strokeWidth={2}
129→          vectorEffect="non-scaling-stroke"
130→          style={{ cursor: 'move' }}
131→        />
132→        <rect
133→          data-handle="end"
134→          x={sectionCut.endPoint.x - handleR / 2}
135→          y={sectionCut.endPoint.y - handleR / 2}
136→          width={handleR}
137→          height={handleR}
138→          fill="white"
139→          stroke="var(--color-selection)"
140→          strokeWidth={2}
141→          vectorEffect="non-scaling-stroke"
142→          style={{ cursor: 'move' }}
143→        />
144→      </g>
145→    );
146→  }
147→
148→  if (selectedType === 'annotation') {
149→    const figure = getManualAnnotationFigure(floor, selectedId);
150→    if (!figure) return null;
151→    return (
152→      <g>
153→        {figure.extensionLines.map((line, index) => (
154→          <line
155→            key={`annotation-ext-${index}`}
156→            x1={line.start.x}
157→            y1={line.start.y}
158→            x2={line.end.x}
159→            y2={line.end.y}
160→            stroke="var(--color-selection)"
161→            strokeWidth={2}
162→            strokeDasharray="6 3"
163→            vectorEffect="non-scaling-stroke"
164→          />
165→        ))}
166→        <line
167→          x1={figure.lineStart.x}
168→          y1={figure.lineStart.y}
169→          x2={figure.lineEnd.x}
170→          y2={figure.lineEnd.y}
171→          stroke="var(--color-selection)"
172→          strokeWidth={2}
173→          strokeDasharray="6 3"
174→          vectorEffect="non-scaling-stroke"
175→        />
176→      </g>
177→    );
178→  }
179→
180→  if (selectedType === 'door') {
181→    const door = floor.doors.find(d => d.id === selectedId);
182→    if (!door) return null;
183→    const wall = floor.walls.find(w => w.id === door.wallId);
184→    if (!wall) return null;
185→    // Highlight parent wall subtly
186→    const outline = getWallRenderData(wall, floor.columns || []).outline;
187→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
188→    return (
189→      <polygon
190→        points={points}
191→        fill="none"
