296→            fill="white"
297→            stroke="var(--color-selection)"
298→            strokeWidth={2}
299→            vectorEffect="non-scaling-stroke"
300→            style={{ cursor: 'move' }}
301→          />
302→        ))}
303→      </g>
304→    );
305→  }
306→
307→  if (selectedType === 'fixture') {
308→    const fixture = (floor.fixtures || []).find(f => f.id === selectedId);
309→    if (!fixture) return null;
310→    const outline = fixtureOutline(fixture);
311→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
312→    return (
313→      <polygon
314→        points={points}
315→        fill="var(--color-selection-fill)"
316→        stroke="var(--color-selection)"
317→        strokeWidth={2}
318→        strokeDasharray="6 3"
319→        vectorEffect="non-scaling-stroke"
320→      />
321→    );
322→  }
323→
324→  if (selectedType === 'room') {
325→    const room = floor.rooms.find(r => r.id === selectedId);
326→    if (!room?.points?.length) return null;
327→    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
328→    return (
329→      <polygon
330→        points={points}
331→        fill="none"
332→        stroke="var(--color-selection)"
333→        strokeWidth={2}
334→        strokeDasharray="6 3"
335→        vectorEffect="non-scaling-stroke"
336→      />
337→    );
338→  }
339→
340→  return null;
341→}
