 44→function screenToModel(screenX, screenY, viewport, svgRect) {
 45→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 46→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 47→  return { x, y };
 48→}
